package com.evolua.social.interfaces.rest; import com.evolua.social.application.PostService; import com.evolua.social.infrastructure.security.CurrentUserProvider; import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import java.util.List; import org.springframework.http.HttpStatus; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/v1/posts") public class PostController { private final PostService service; private final PostMapper mapper; private final CurrentUserProvider currentUserProvider; public PostController(PostService service, PostMapper mapper, CurrentUserProvider currentUserProvider) { this.service = service; this.mapper = mapper; this.currentUserProvider = currentUserProvider; } @PostMapping @Operation(summary = "Create Post") public ResponseEntity<ApiResponse<PostResponse>> create(@Valid @RequestBody PostRequest request) { var created = service.create(currentUserProvider.getCurrentUser().userId(), request.content(), request.community(), request.visibility()); return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(201, "Created", mapper.toResponse(created))); } @GetMapping @Operation(summary = "List posts") public ResponseEntity<ApiResponse<List<PostResponse>>> list() { return ResponseEntity.ok(ApiResponse.success(200, "Listed", service.list(currentUserProvider.getCurrentUser().userId()).stream().map(mapper::toResponse).toList())); } }
